/**
 * THACO E-MENU - CLOUDFLARE WORKER (VERSION 10.2 - POLLING MODE)
 * Status: Full Stack (Backend + Frontend UI)
 */

const CORS_HEADERS = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, x-admin-pass',
  };
  
  export default {
    async fetch(request, env, ctx) {
      if (request.method === 'OPTIONS') return new Response(null, { headers: CORS_HEADERS });
      const url = new URL(request.url);
      const path = url.pathname;
      
      // --- ROUTING GIAO DIỆN ---
      if (path === '/admin') return new Response(HTML_ADMIN, { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
      if (path === '/kitchen') return new Response(HTML_KITCHEN, { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
      if (path === '/' || path === '/index.html') return new Response(HTML_CLIENT, { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
  
      // --- ROUTING API ---
      try {
        // PUBLIC
        if (path === '/api/getLocations') return await getPublicLocations(request, env);
        if (path === '/api/getLocationInfo') return await getLocationInfo(request, env);
        if (path === '/api/getMenu') return await getMenuByLocation(request, env);
        if (path === '/api/getBanners') return await getBanners(request, env);
        if (path === '/api/getTags') return await getTagsPublic(request, env);
        
        // ORDER
        if (path === '/api/createOrder') return await createOrder(request, env);
        if (path === '/api/updateOrderContent') return await updateOrderContent(request, env);
        if (path === '/api/cancelOrderClient') return await cancelOrderClient(request, env);
        if (path === '/api/getOrderStatus') return await getOrderStatus(request, env);
        if (path === '/api/getMyOrders') return await getMyOrders(request, env);
  
        // KITCHEN
        if (path === '/api/kitchen/login') return await kitchenLogin(request, env);
        if (path === '/api/getOrders') return await getOrders(request, env);
        if (path === '/api/updateOrderStatus') return await updateOrderStatus(request, env);
        if (path === '/api/cancelOrder') return await cancelOrder(request, env);
        if (path === '/api/kitchen/getReport') return await getKitchenReport(request, env);
        if (path === '/api/checkSync') return await checkSync(request, env);
  
        // ADMIN
        if (path.startsWith('/api/admin/')) {
          const authorized = await checkAdminAuth(request, env);
          if (!authorized) return new Response(JSON.stringify({ success: false, message: 'Sai mật khẩu Admin' }), { status: 401, headers: CORS_HEADERS });
  
          if (path === '/api/admin/login') return createResponse({ success: true });
          if (path === '/api/admin/getLocations') return await getLocations(request, env);
          if (path === '/api/admin/saveLocation') return await saveLocation(request, env);
          if (path === '/api/admin/uploadImage') return await uploadImageToR2(request, env);
          if (path === '/api/admin/getMasterMenu') return await getMasterMenu(request, env);
          if (path === '/api/admin/saveMasterMenu') return await saveMasterMenuAndPartition(request, env);
          if (path === '/api/admin/getTags') return await getTagsAdmin(request, env);
          if (path === '/api/admin/saveTags') return await saveTags(request, env);
          if (path === '/api/admin/getBanners') return await getBannersAdmin(request, env);
          if (path === '/api/admin/saveBanners') return await saveBanners(request, env);
          if (path === '/api/admin/getTables') return await getTablesByLocation(request, env);
          if (path === '/api/admin/saveTables') return await saveTablesByLocation(request, env);
          if (path === '/api/admin/getReportData') return await getReportData(request, env);
          if (path === '/api/admin/triggerExport') return await triggerManualExport(request, env);
        }
        return new Response('Not Found', { status: 404 });
      } catch (e) {
        return createResponse({ success: false, message: e.message });
      }
    },
    async scheduled(event, env, ctx) {
        await exportDailyReport(env);
      },
  };

  // --- CẤU HÌNH SHEET ---
  const REPORT_WEBHOOK_URL = "https://script.google.com/macros/s/AKfycbyJAtdTVvPP9FfP5BslewAskReqD11mkUnoZAaCGTA-RUyUi5J4eNhRlLSHkgXxhbAO/exec"; 
  const REPORT_SECRET = "THACO_REPORT_SECRET_2026"; 

  async function triggerManualExport(req, env) {
    try {
        await exportDailyReport(env); 
        return createResponse({ success: true, message: 'Đã xuất dữ liệu thành công sang Google Sheet.' });
    } catch (e) {
        return createResponse({ success: false, message: 'Lỗi xuất dữ liệu: ' + e.message });
    }
  }

  // --- HELPER & CORE ---
  function createResponse(data) { return new Response(JSON.stringify(data), { headers: { ...CORS_HEADERS, 'Content-Type': 'application/json' } }); }
  async function checkAdminAuth(req, env) { let p = req.headers.get('x-admin-pass'); if (!p) { try { const b = await req.clone().json(); p = b.password; } catch (e) {} } return p === env.ADMIN_PASSWORD; }
  function normalizeId(id) { return id ? id.toString().trim().toUpperCase() : ''; }
  async function updateTrigger(env, locId) { await env.DB.put(`sync:${normalizeId(locId)}`, Date.now().toString()); }
  
  // --- 1. ADMIN LOGIC ---
  async function uploadImageToR2(req, env) { const fd = await req.formData(); const f = fd.get('file'); if (!f) throw new Error('No file'); const k = `img_${Date.now()}_${Math.floor(Math.random() * 1000)}`; await env.BUCKET.put(k, f); return createResponse({ success: true, url: `${env.IMAGE_HOST}/${k}` }); }
  async function getMasterMenu(req, env) { return createResponse({ success: true, data: await env.DB.get('menu:master', { type: 'json' }) || [] }); }
  async function saveMasterMenuAndPartition(req, env) { 
      const m = await req.json(); await env.DB.put('menu:master', JSON.stringify(m));
      const locs = await env.DB.get('locations', { type: 'json' }) || [];
      for (const l of locs) { const lid = normalizeId(l.id); const lm = m.filter(i => i.locations.some(x => x === 'all' || normalizeId(x) === lid)); await env.DB.put(`menu:${lid}`, JSON.stringify(lm)); }
      return createResponse({ success: true }); 
  }
  async function getLocations(req, env) { return createResponse({ success: true, data: await env.DB.get('locations', { type: 'json' }) || [] }); }
  async function saveLocation(req, env) { await env.DB.put('locations', JSON.stringify(await req.json())); return createResponse({ success: true }); }
  async function getBannersAdmin(req, env) { return createResponse({ success: true, data: await env.DB.get('banners', { type: 'json' }) || [] }); }
  async function saveBanners(req, env) { await env.DB.put('banners', JSON.stringify(await req.json())); return createResponse({ success: true }); }
  async function getTablesByLocation(req, env) { const lid = normalizeId(new URL(req.url).searchParams.get('locationId')); const d = await env.DB.get(`tables:${lid}`, { type: 'json' }) || []; return createResponse({ success: true, data: d }); }
  async function saveTablesByLocation(req, env) { const { locationId, tables } = await req.json(); await env.DB.put(`tables:${normalizeId(locationId)}`, JSON.stringify(tables)); return createResponse({ success: true }); }
  async function getTagsAdmin(req, env) { const t = await env.DB.get('tags:master', { type: 'json' }) || []; return createResponse({ success: true, data: t.length ? t : [{id:'new',name:'MỚI',color:'#22c55e'},{id:'hot',name:'HOT',color:'#ef4444'}] }); }
  async function saveTags(req, env) { await env.DB.put('tags:master', JSON.stringify(await req.json())); return createResponse({ success: true }); }
  async function getReportData(req, env) {
      const { locationId, startDate, endDate } = await req.json(); const lid = normalizeId(locationId); const list = await env.DB.list({ prefix: `order:${lid}:` }); const orders = []; const s = new Date(startDate).getTime(); const e = new Date(endDate).getTime() + 86399999;
      for (const k of list.keys) { const ts = parseInt(k.name.split(':')[2]); if (ts >= s && ts <= e) { const o = await env.DB.get(k.name, { type: 'json' }); if (o) orders.push(o); } }
      orders.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)); return createResponse({ success: true, data: orders });
  }
  
  // --- EXPORT LOGIC ---
  async function exportDailyReport(env) {
    const now = new Date();
    const vnTimeStr = now.toLocaleString("en-US", {timeZone: "Asia/Ho_Chi_Minh"});
    const startOfDay = new Date(vnTimeStr);
    startOfDay.setHours(0,0,0,0);
    const startTs = startOfDay.getTime();
    const endTs = startTs + 86400000;
    const dateStr = startOfDay.toLocaleDateString('vi-VN');
    const locations = await env.DB.get('locations', { type: 'json' }) || [];
    let allRows = [];

    for (const loc of locations) {
        const lid = normalizeId(loc.id);
        const lname = loc.name;
        const list = await env.DB.list({ prefix: `order:${lid}:` });
        for (const k of list.keys) {
            const parts = k.name.split(':');
            const timestamp = parseInt(parts[2]);
            if (timestamp >= startTs && timestamp < endTs) {
                const order = await env.DB.get(k.name, { type: 'json' });
                if (order && order.status === 'completed') {
                    if (order.items) {
                        order.items.forEach(item => {
                            const timeStr = new Date(order.createdAt).toLocaleTimeString('vi-VN', {timeZone: "Asia/Ho_Chi_Minh"});
                            allRows.push([timeStr, dateStr, lid, lname, order.orderId, item.name, item.quantity, order.status]);
                        });
                    }
                }
            }
        }
    }

    if (allRows.length > 0) {
        try {
            await fetch(REPORT_WEBHOOK_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ token: REPORT_SECRET, data: allRows })
            });
        } catch (e) {
            console.error("Export Error:", e);
            throw e;
        }
    }
}

  // --- 2. CLIENT LOGIC ---
  async function getPublicLocations(req, env) { const l = await env.DB.get('locations', { type: 'json' }) || []; return createResponse({ success: true, data: l.map(x => ({ id: x.id, name: x.name })) }); }
  async function getLocationInfo(req, env) { const l = await env.DB.get('locations', { type: 'json' }) || []; const tid = normalizeId(new URL(req.url).searchParams.get('locationId')); const f = l.find(x => normalizeId(x.id) === tid); return f ? createResponse({ success: true, data: f }) : createResponse({ success: false }); }
  async function getMenuByLocation(req, env) { 
      const lid = normalizeId(new URL(req.url).searchParams.get('locationId')); let m = await env.DB.get(`menu:${lid}`, { type: 'json' });
      if (!m) { const master = await env.DB.get('menu:master', { type: 'json' }) || []; m = master.filter(i => i.locations.some(l => l === 'all' || normalizeId(l) === lid)); }
      return createResponse({ success: true, data: m || [] });
  }
  async function getBanners(req, env) { const lid = normalizeId(new URL(req.url).searchParams.get('locationId')); const all = await env.DB.get('banners', { type: 'json' }) || []; return createResponse({ success: true, data: all.filter(b => normalizeId(b.locationId) === lid || b.locationId === 'all' || normalizeId(b.locationId) === 'ALL') }); }
  async function getTagsPublic(req, env) { return createResponse({ success: true, data: await env.DB.get('tags:master', { type: 'json' }) || [] }); }
  async function createOrder(req, env) {
    const d = await req.json(); const lid = normalizeId(d.locationId); const ts = Date.now(); const oid = (lid + '-' + ts.toString().slice(-6)).toUpperCase();
    const o = { ...d, locationId: lid, orderId: oid, status: 'pending', createdAt: new Date().toISOString() };
    await env.DB.put(`order:${lid}:${ts}:${oid}`, JSON.stringify(o), { expirationTtl: 86400 * 7 }); await updateTrigger(env, lid);
    return createResponse({ success: true, data: { orderId: oid } });
  }
  async function updateOrderContent(req, env) {
      const d = await req.json(); const lid = normalizeId(d.locationId); const list = await env.DB.list({ prefix: `order:${lid}:` }); const k = list.keys.find(x => x.name.includes(d.orderId));
      if(!k) return createResponse({ success: false, message: 'Not found' }); const o = await env.DB.get(k.name, { type: 'json' });
      if(o.status !== 'pending') return createResponse({ success: false, message: 'Locked' });
      o.items = d.items; o.notes = d.notes; o.customerName = d.customerName; o.phoneNumber = d.phoneNumber;
      await env.DB.put(k.name, JSON.stringify(o), { expirationTtl: 86400 * 7 }); await updateTrigger(env, lid);
      return createResponse({ success: true, data: { orderId: o.orderId } });
  }
  async function cancelOrderClient(req, env) {
      const d = await req.json(); const lid = normalizeId(d.locationId); const list = await env.DB.list({ prefix: `order:${lid}:` }); const k = list.keys.find(x => x.name.includes(d.orderId));
      if(k) { const o = await env.DB.get(k.name, { type: 'json' }); if(o.status === 'pending') { o.status = 'cancelled'; o.cancelReason = 'Khách hủy'; await env.DB.put(k.name, JSON.stringify(o), { expirationTtl: 86400 * 7 }); await updateTrigger(env, lid); return createResponse({ success: true }); } return createResponse({ success: false, message: 'Locked' }); }
      return createResponse({ success: false });
  }
  async function getMyOrders(req, env) {
      const { locationId, orderIds } = await req.json(); const lid = normalizeId(locationId); const list = await env.DB.list({ prefix: `order:${lid}:` }); const res = [];
      for (const k of list.keys) { if (orderIds.some(oid => k.name.includes(oid))) { const o = await env.DB.get(k.name, { type: 'json' }); if(o) res.push(o); } }
      res.sort((a,b) => new Date(b.createdAt) - new Date(a.createdAt)); return createResponse({ success: true, data: res });
  }
  async function getOrderStatus(req, env) { const oid = new URL(req.url).searchParams.get('orderId').toUpperCase(); const lid = normalizeId(new URL(req.url).searchParams.get('locationId')); const list = await env.DB.list({ prefix: `order:${lid}:` }); const k = list.keys.find(x => x.name.includes(oid)); if (k) { const o = await env.DB.get(k.name, { type: 'json' }); if (o) return createResponse({ success: true, data: o }); } return createResponse({ success: false }); }
  
  // --- 3. KITCHEN LOGIC ---
  async function kitchenLogin(req, env) { const { locationId, password } = await req.json(); const l = (await env.DB.get('locations', { type: 'json' }) || []).find(x => normalizeId(x.id) === normalizeId(locationId)); return createResponse({ success: l && l.kitchenPass === password }); }
  async function verifyKitchenAuth(env, lid, pass) { const l = (await env.DB.get('locations', { type: 'json' }) || []).find(x => normalizeId(x.id) === normalizeId(lid)); return l && l.kitchenPass === pass; }
  async function checkSync(req, env) { const lid = normalizeId(new URL(req.url).searchParams.get('locationId')); const ls = await env.DB.get(`sync:${lid}`); return createResponse({ success: true, lastSync: ls || '0' }); }
  async function getOrders(req, env) { const lid = normalizeId(new URL(req.url).searchParams.get('locationId')); const list = await env.DB.list({ prefix: `order:${lid}:` }); const res = []; for (const k of list.keys) { const o = await env.DB.get(k.name, { type: 'json' }); if (o) res.push(o); } return createResponse({ success: true, data: res.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)) }); }
  async function updateOrderStatus(req, env) {
    const d = await req.json(); const lid = normalizeId(d.locationId); const list = await env.DB.list({ prefix: `order:${lid}:` });
    for (const k of list.keys) { if (k.name.includes(d.orderId)) { const o = await env.DB.get(k.name, { type: 'json' }); o.status = d.status; await env.DB.put(k.name, JSON.stringify(o), { expirationTtl: 86400 * 7 }); await updateTrigger(env, lid); return createResponse({ success: true }); } }
    return createResponse({ success: false });
  }
  async function cancelOrder(req, env) { 
      const d = await req.json(); const lid = normalizeId(d.locationId); const list = await env.DB.list({ prefix: `order:${lid}:` });
      for (const k of list.keys) { if (k.name.includes(d.orderId)) { const o = await env.DB.get(k.name, { type: 'json' }); o.status = 'cancelled'; o.cancelReason = d.reason; await env.DB.put(k.name, JSON.stringify(o), { expirationTtl: 86400 * 7 }); await updateTrigger(env, lid); return createResponse({ success: true }); } }
      return createResponse({ success: false });
  }
  async function getKitchenReport(req, env) {
      const { locationId, password, type, date } = await req.json(); if (!(await verifyKitchenAuth(env, locationId, password))) return createResponse({ success: false, message: 'Sai mật khẩu' });
      const lid = normalizeId(locationId); const list = await env.DB.list({ prefix: `order:${lid}:` }); const t = new Date(date); let s, e;
      if (type === 'day') { s = new Date(t.setHours(0,0,0,0)).getTime(); e = new Date(t.setHours(23,59,59,999)).getTime(); }
      else if (type === 'week') { const day = t.getDay(); const diff = t.getDate() - day + (day == 0 ? -6 : 1); const m = new Date(t.setDate(diff)); s = new Date(m.setHours(0,0,0,0)).getTime(); e = s + (7 * 24 * 60 * 60 * 1000) - 1; }
      else if (type === 'month') { s = new Date(t.getFullYear(), t.getMonth(), 1).getTime(); e = new Date(t.getFullYear(), t.getMonth() + 1, 0, 23, 59, 59).getTime(); }
      const rep = {}; 
      for (const k of list.keys) { const ts = parseInt(k.name.split(':')[2]); if (ts >= s && ts <= e) { const o = await env.DB.get(k.name, { type: 'json' }); if (o && ['preparing', 'ready', 'completed'].includes(o.status)) { o.items.forEach(i => { const q = parseInt(i.quantity) || 0; rep[i.name] = (rep[i.name] || 0) + q; }); } } }
      const rd = Object.keys(rep).map(k => ({ name: k, quantity: rep[k] })); rd.sort((a,b) => b.quantity - a.quantity);
      return createResponse({ success: true, data: rd });
  }
  
  // --- HTML ADMIN ---
  const HTML_ADMIN = `<!DOCTYPE html><html lang="vi"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Admin</title><script src="https://cdn.tailwindcss.com"></script><link href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0/css/all.min.css" rel="stylesheet"><script>tailwind.config={theme:{extend:{colors:{thaco:'#003468',thacoLight:'#005a9e'}}}}</script></head><body class="bg-gray-100 font-sans text-gray-800"><div id="loginScreen" class="fixed inset-0 bg-thaco flex items-center justify-center z-50"><div class="bg-white p-8 rounded-lg shadow-2xl w-96 text-center"><h2 class="text-2xl font-bold text-thaco mb-6">QUẢN TRỊ</h2><input type="password" id="adminPass" placeholder="Mật khẩu..." class="w-full p-3 border rounded mb-4" onkeypress="if(event.key==='Enter') doLogin()"><button onclick="doLogin()" class="w-full bg-thaco text-white py-3 rounded font-bold hover:bg-thacoLight">ĐĂNG NHẬP</button></div></div><div id="adminContent" class="hidden min-h-screen flex flex-col"><nav class="bg-thaco text-white shadow-lg sticky top-0 z-40"><div class="max-w-7xl mx-auto px-4 py-3 flex justify-between items-center"><div class="text-xl font-bold flex items-center gap-2"><i class="fas fa-cogs"></i> THACO ADMIN</div><button onclick="logout()" class="text-sm bg-red-600 px-3 py-1 rounded hover:bg-red-700">Đăng xuất</button></div></nav><div class="bg-white shadow sticky top-14 z-30"><div class="max-w-7xl mx-auto flex overflow-x-auto"><button onclick="switchTab('menu')" id="tab-menu" class="flex-1 py-4 px-4 font-bold border-b-2 border-transparent hover:text-thaco">Menu</button><button onclick="switchTab('tags')" id="tab-tags" class="flex-1 py-4 px-4 font-bold border-b-2 border-transparent hover:text-thaco">Tags</button><button onclick="switchTab('banners')" id="tab-banners" class="flex-1 py-4 px-4 font-bold border-b-2 border-transparent hover:text-thaco">Banner</button><button onclick="switchTab('locations')" id="tab-locations" class="flex-1 py-4 px-4 font-bold border-b-2 border-transparent hover:text-thaco">Địa điểm</button><button onclick="switchTab('info')" id="tab-info" class="flex-1 py-4 px-4 font-bold border-b-2 border-transparent hover:text-thaco">Báo cáo</button></div></div><div class="max-w-7xl mx-auto w-full p-4 flex-1"><div id="content-menu" class="hidden tab-content"><div class="flex justify-between items-center mb-4"><h3 class="text-xl font-bold text-thaco">Menu Master</h3><button onclick="openMenuModal()" class="bg-thaco text-white px-4 py-2 rounded text-sm font-bold">+ Thêm Món</button></div><div id="menuList" class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">Loading...</div></div><div id="content-tags" class="hidden tab-content"><div class="flex justify-between items-center mb-4"><h3 class="text-xl font-bold text-thaco">Quản lý Tags & Nhãn</h3><button onclick="addTag()" class="bg-blue-600 text-white px-4 py-2 rounded text-sm font-bold">+ Thêm Tag</button></div><div id="tagsList" class="space-y-2">Loading...</div></div><div id="content-banners" class="hidden tab-content"><div class="flex justify-between items-center mb-4"><h3 class="text-xl font-bold text-thaco">Quản lý Banner</h3><button onclick="openBannerModal()" class="bg-green-600 text-white px-4 py-2 rounded text-sm font-bold">+ Thêm Banner</button></div><div id="bannerList" class="grid grid-cols-1 md:grid-cols-2 gap-4">Loading...</div></div><div id="content-locations" class="hidden tab-content"><div class="bg-white p-4 rounded shadow mb-6"><h4 class="font-bold text-lg mb-4 text-thaco" id="formLocTitle">Thêm Địa điểm mới</h4><div class="grid grid-cols-1 md:grid-cols-2 gap-4"><input id="newLocId" placeholder="Mã (VD: CN_HCM)" class="p-2 border rounded"><input id="newLocName" placeholder="Tên hiển thị" class="p-2 border rounded"><input id="newLocPass" placeholder="Pass Bếp" class="p-2 border rounded"><input id="newLocAddr" placeholder="Địa chỉ" class="p-2 border rounded"><div class="flex gap-2 col-span-1 md:col-span-2"><button id="btnAddLoc" onclick="addLocation()" class="flex-1 bg-green-600 text-white py-2 rounded font-bold hover:bg-green-700">Thêm Mới</button><button id="btnCancelLoc" onclick="resetLocForm()" class="hidden w-20 bg-gray-400 text-white py-2 rounded font-bold hover:bg-gray-500">Hủy</button></div></div></div><h3 class="text-xl font-bold text-thaco mb-4">Danh sách Địa điểm</h3><div id="locList" class="space-y-4">Loading...</div></div><div id="content-info" class="hidden tab-content"><div class="bg-white p-6 rounded shadow mb-6"><h3 class="text-xl font-bold text-thaco mb-4">Thống kê</h3><div class="flex flex-wrap gap-4 items-end mb-6"><div><label class="block text-sm font-bold mb-1">Từ ngày:</label><input type="date" id="reportStart" class="p-2 border rounded w-40"></div><div><label class="block text-sm font-bold mb-1">Đến ngày:</label><input type="date" id="reportEnd" class="p-2 border rounded w-40"></div><div class="flex-1"><label class="block text-sm font-bold mb-1">Địa điểm:</label><select id="reportLocSelect" class="w-full p-2 border rounded"></select></div><button onclick="loadReports()" class="bg-thaco text-white px-6 py-2 rounded font-bold h-10">Xem Báo Cáo</button></div><div id="reportResults" class="overflow-x-auto"></div><div class="mt-6 pt-4 border-t border-gray-200"><h4 class="font-bold text-gray-700 mb-2">Đồng bộ dữ liệu</h4><div class="flex items-center gap-3"><button onclick="triggerExport()" id="btnExport" class="bg-green-600 text-white px-6 py-2 rounded font-bold hover:bg-green-700 flex items-center gap-2 shadow transition active:scale-95"><i class="fas fa-file-excel"></i> Xuất Báo Cáo Ngay (Sheet)</button><span class="text-xs text-gray-500 italic">* Hệ thống sẽ tự động xuất lúc 23:55. Bấm nút này để xuất thủ công ngay lập tức (dữ liệu hôm nay).</span></div></div></div></div></div><div id="menuModal" class="fixed inset-0 bg-black bg-opacity-50 hidden items-center justify-center z-50"><div class="bg-white rounded-lg w-full max-w-2xl p-6 relative h-[90vh] overflow-y-auto"><button onclick="closeModal('menuModal')" class="absolute top-4 right-4 text-2xl text-gray-500">&times;</button><h3 id="modalTitle" class="text-xl font-bold text-thaco mb-4">Thêm/Sửa Món</h3><input type="hidden" id="editIndex"><div class="grid grid-cols-2 gap-4"><div class="col-span-2 space-y-3"><input id="itemName" placeholder="Tên món" class="w-full p-2 border rounded"><input id="itemCategory" placeholder="Danh mục" list="catSuggestions" class="w-full p-2 border rounded"><datalist id="catSuggestions"></datalist><textarea id="itemDesc" placeholder="Mô tả" class="w-full p-2 border rounded" rows="2"></textarea></div><div class="col-span-1 border p-3 rounded"><p class="text-sm font-bold mb-2">Hình ảnh</p><input type="file" id="itemImageFile" accept="image/*" class="text-sm w-full mb-2"><button onclick="uploadImage('itemImageFile', 'itemImageUrl', 'previewImg')" class="bg-gray-200 px-3 py-1 rounded text-xs">Upload</button><input id="itemImageUrl" class="w-full p-2 bg-gray-100 border rounded text-xs mt-2" readonly><img id="previewImg" class="h-20 w-auto mt-2 hidden border"></div><div class="col-span-1 border p-3 rounded"><p class="text-sm font-bold mb-2">Tags:</p><div id="tagsContainer" class="space-y-1 max-h-24 overflow-y-auto"></div></div><div class="col-span-2 border p-3 rounded"><p class="text-sm font-bold mb-2">Tùy chọn:</p><div id="optionsContainer" class="space-y-3"></div><button onclick="addOptionGroup()" class="mt-2 text-blue-600 text-sm font-bold">+ Thêm nhóm tùy chọn</button></div></div><div class="mt-6 flex justify-end gap-3 pt-4 border-t"><button onclick="closeModal('menuModal')" class="px-4 py-2 border rounded">Hủy</button><button onclick="saveMenuItem()" class="bg-thaco text-white px-6 py-2 rounded font-bold">Lưu</button></div></div></div><div id="bannerModal" class="fixed inset-0 bg-black bg-opacity-50 hidden items-center justify-center z-50"><div class="bg-white rounded-lg w-full max-w-md p-6 relative"><button onclick="closeModal('bannerModal')" class="absolute top-4 right-4 text-2xl text-gray-500">&times;</button><h3 id="bannerModalTitle" class="text-xl font-bold text-thaco mb-4">Banner</h3><input type="hidden" id="editBannerIndex"><div class="space-y-4"><div class="border p-3 rounded"><p class="text-sm font-bold mb-2">Hình ảnh</p><input type="file" id="bannerFile" accept="image/*" class="text-sm w-full mb-2"><button onclick="uploadImage('bannerFile', 'bannerUrl', 'previewBanner')" class="bg-gray-200 px-3 py-1 rounded text-xs">Upload</button><input id="bannerUrl" class="w-full p-2 bg-gray-100 border rounded text-xs mt-2" readonly><img id="previewBanner" class="h-24 w-full object-cover hidden border mt-2"></div><div><p class="text-sm font-bold mb-1">Link đích:</p><input id="bannerLink" placeholder="https://..." class="w-full p-2 border rounded"></div><div><p class="text-sm font-bold mb-1">Áp dụng cho:</p><select id="bannerLocSelect" class="w-full p-2 border rounded"></select></div></div><div class="mt-6 flex justify-end gap-3"><button onclick="closeModal('bannerModal')" class="px-4 py-2 border rounded">Hủy</button><button onclick="saveBanner()" class="bg-green-600 text-white px-6 py-2 rounded font-bold">Lưu</button></div></div></div><div id="tableModal" class="fixed inset-0 bg-black bg-opacity-50 hidden items-center justify-center z-50"><div class="bg-white rounded-lg w-full max-w-lg p-6 relative h-[80vh] flex flex-col"><button onclick="closeModal('tableModal')" class="absolute top-4 right-4 text-2xl text-gray-500">&times;</button><h3 id="tableModalTitle" class="text-xl font-bold text-thaco mb-4">Quản lý Bàn</h3><div class="flex gap-2 mb-4"><input id="newTableName" placeholder="Tên bàn (VD: Bàn 1)" class="flex-1 p-2 border rounded"><button onclick="addTableToCurrentLoc()" class="bg-blue-600 text-white px-4 rounded font-bold">Thêm</button></div><div id="tableListContainer" class="flex-1 overflow-y-auto space-y-2 border-t pt-2"></div></div></div><div id="configMenuModal" class="fixed inset-0 bg-black bg-opacity-50 hidden items-center justify-center z-50"><div class="bg-white rounded-lg w-full max-w-4xl p-6 relative h-[90vh] flex flex-col"><button onclick="closeModal('configMenuModal')" class="absolute top-4 right-4 text-2xl text-gray-500">&times;</button><h3 id="configMenuTitle" class="text-xl font-bold text-thaco mb-4">Cấu hình Menu</h3><p class="text-sm text-gray-500 mb-4">Chọn các món ăn sẽ hiển thị tại địa điểm này.</p><div id="configMenuGrid" class="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 flex-1 overflow-y-auto p-2 border rounded bg-gray-50"></div><div class="mt-4 pt-4 border-t flex justify-end"><button onclick="saveLocationMenuConfig()" class="bg-thaco text-white px-8 py-3 rounded font-bold">Lưu Cấu Hình</button></div></div></div><script>const API='/api/admin';let locations=[],masterMenu=[],banners=[],tables=[],masterTags=[];let editingLocIndex=-1,currentEditingLocId=null;document.addEventListener('DOMContentLoaded',()=>{const savedPass=localStorage.getItem('adminPass');if(savedPass){document.getElementById('adminPass').value=savedPass;doLogin()}});function doLogin(){const pass=document.getElementById('adminPass').value;fetch(API+'/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({password:pass})}).then(res=>{if(res.ok){localStorage.setItem('adminPass',pass);document.getElementById('loginScreen').classList.add('hidden');document.getElementById('adminContent').classList.remove('hidden');init()}else{alert('Sai mật khẩu');localStorage.removeItem('adminPass')}}).catch(e=>{alert('Lỗi kết nối')})}function logout(){localStorage.removeItem('adminPass');location.reload()}function getHeaders(){return{'Content-Type':'application/json','x-admin-pass':localStorage.getItem('adminPass')}}function openModal(id){document.getElementById(id).classList.remove('hidden');document.getElementById(id).classList.add('flex')}function closeModal(id){document.getElementById(id).classList.add('hidden');document.getElementById(id).classList.remove('flex')}async function init(){document.getElementById('reportStart').valueAsDate=new Date();document.getElementById('reportEnd').valueAsDate=new Date();await Promise.all([loadLocations(),loadMenu(),loadBanners(),loadTables(),loadTags()]);switchTab('menu')}function switchTab(tabId){document.querySelectorAll('.tab-content').forEach(el=>el.classList.add('hidden'));document.getElementById('content-'+tabId).classList.remove('hidden');document.querySelectorAll('[id^="tab-"]').forEach(btn=>btn.classList.remove('border-thaco','text-thaco'));document.getElementById('tab-'+tabId).classList.add('border-thaco','text-thaco')}async function loadLocations(){const res=await fetch(API+'/getLocations',{headers:getHeaders()});const json=await res.json();locations=json.data||[];renderLocs();const opts=locations.map(l=>\`<option value="\${l.id}">\${l.name}</option>\`).join('');document.getElementById('bannerLocSelect').innerHTML='<option value="all">Toàn hệ thống</option>'+opts;document.getElementById('reportLocSelect').innerHTML=opts}function renderLocs(){const list=document.getElementById('locList');list.innerHTML=locations.map((l,i)=>\`<div class="bg-white p-4 rounded shadow border-l-4 border-thaco flex flex-col md:flex-row justify-between items-center gap-4"><div class="flex-1"><div class="font-bold text-lg text-thaco">\${l.name}</div><div class="text-sm text-gray-500">ID: <b>\${l.id}</b></div><div class="text-sm text-gray-500">\${l.address||'Chưa cập nhật địa chỉ'}</div></div><div class="flex gap-2"><button onclick="openTableManager('\${l.id}')" class="bg-blue-100 text-blue-700 px-3 py-2 rounded text-sm font-bold hover:bg-blue-200"><i class="fas fa-qrcode"></i> Bàn & QR</button><button onclick="openMenuConfig('\${l.id}')" class="bg-yellow-100 text-yellow-700 px-3 py-2 rounded text-sm font-bold hover:bg-yellow-200"><i class="fas fa-list-check"></i> Cấu hình Menu</button><button onclick="editLoc(\${i})" class="bg-gray-100 text-blue-700 px-3 py-2 rounded text-sm font-bold hover:bg-gray-200"><i class="fas fa-edit"></i> Sửa</button><button onclick="delLoc(\${i})" class="bg-red-100 text-red-700 px-3 py-2 rounded text-sm font-bold hover:bg-red-200"><i class="fas fa-trash"></i></button></div></div>\`).join('');resetLocForm()}function editLoc(i){editingLocIndex=i;const l=locations[i];document.getElementById('newLocId').value=l.id;document.getElementById('newLocId').disabled=true;document.getElementById('newLocName').value=l.name;document.getElementById('newLocPass').value=l.kitchenPass;document.getElementById('newLocAddr').value=l.address||'';document.getElementById('formLocTitle').innerText='Cập nhật Showroom:';document.getElementById('btnAddLoc').innerText='Lưu Thay Đổi';document.getElementById('btnAddLoc').onclick=updateLocation;document.getElementById('btnCancelLoc').classList.remove('hidden')}function resetLocForm(){editingLocIndex=-1;document.getElementById('newLocId').value='';document.getElementById('newLocId').disabled=false;document.getElementById('newLocName').value='';document.getElementById('newLocPass').value='';document.getElementById('newLocAddr').value='';document.getElementById('formLocTitle').innerText='Thêm Showroom mới:';document.getElementById('btnAddLoc').innerText='Thêm Mới';document.getElementById('btnAddLoc').onclick=addLocation;document.getElementById('btnCancelLoc').classList.add('hidden')}async function addLocation(){const id=document.getElementById('newLocId').value.toUpperCase().trim();const name=document.getElementById('newLocName').value;const pass=document.getElementById('newLocPass').value;const addr=document.getElementById('newLocAddr').value;if(!id||!name||!pass)return alert('Thiếu thông tin');if(locations.some(l=>l.id===id))return alert('Mã showroom đã tồn tại');locations.push({id,name,kitchenPass:pass,address:addr});await saveLocs()}async function updateLocation(){if(editingLocIndex===-1)return;locations[editingLocIndex].name=document.getElementById('newLocName').value;locations[editingLocIndex].kitchenPass=document.getElementById('newLocPass').value;locations[editingLocIndex].address=document.getElementById('newLocAddr').value;await saveLocs()}async function delLoc(i){if(confirm('Xóa?')){locations.splice(i,1);await saveLocs()}}async function saveLocs(){await fetch(API+'/saveLocation',{method:'POST',headers:getHeaders(),body:JSON.stringify(locations)});loadLocations()}async function loadTables(){const res=await fetch(API+'/getTables',{headers:getHeaders()});const json=await res.json();tables=json.data||[]}function openTableManager(locId){currentEditingLocId=locId;const loc=locations.find(l=>l.id===locId);document.getElementById('tableModalTitle').innerText=\`Quản lý Bàn: \${loc.name}\`;openModal('tableModal');loadTablesForLoc(locId)}async function loadTablesForLoc(locId){document.getElementById('tableListContainer').innerHTML='Loading...';const res=await fetch(\`\${API}/getTables?locationId=\${locId}\`,{headers:getHeaders()});const json=await res.json();tables=json.data||[];renderTableListInModal()}function renderTableListInModal(){const container=document.getElementById('tableListContainer');if(tables.length===0){container.innerHTML='<p class="text-center text-gray-500 py-4">Chưa có bàn nào.</p>';return}container.innerHTML=tables.map(t=>{const link=window.location.origin+'/?l='+currentEditingLocId+'&t='+encodeURIComponent(t.name);const qrApi='https://api.qrserver.com/v1/create-qr-code/?size=100x100&data='+encodeURIComponent(link);return\`<div class="flex items-center justify-between p-3 border rounded bg-gray-50"><div class="flex items-center gap-3"><img src="\${qrApi}" class="w-12 h-12 border bg-white"><div><div class="font-bold">\${t.name} <span class="text-xs text-gray-400">(\${t.area||'General'})</span></div><a href="\${link}" target="_blank" class="text-xs text-blue-500 hover:underline">Link đặt món</a></div></div><button onclick="delTable('\${t.id}')" class="text-red-500 hover:text-red-700 px-2"><i class="fas fa-trash"></i></button></div>\`}).join('')}async function addTableToCurrentLoc(){const name=document.getElementById('newTableName').value.trim();if(!name)return alert('Nhập tên bàn');const id=\`\${currentEditingLocId}_\${name}\`;if(tables.some(t=>t.id===id))return alert('Bàn này đã tồn tại');tables.push({id,name,position:currentEditingLocId,area:'General'});await saveTables();document.getElementById('newTableName').value=''}async function delTable(id){if(confirm('Xóa bàn?')){tables=tables.filter(t=>t.id!==id);await saveTables()}}async function saveTables(){await fetch(API+'/saveTables',{method:'POST',headers:getHeaders(),body:JSON.stringify({locationId:currentEditingLocId,tables:tables})});renderTableListInModal()}function openMenuConfig(locId){currentEditingLocId=locId;const loc=locations.find(l=>l.id===locId);document.getElementById('configMenuTitle').innerText=\`Cấu hình Menu cho: \${loc.name}\`;openModal('configMenuModal');const grid=document.getElementById('configMenuGrid');grid.innerHTML=masterMenu.map(item=>{const isChecked=item.locations.includes('all')||item.locations.includes(locId);const isAll=item.locations.includes('all');return\`<label class="flex items-start gap-2 p-3 border rounded bg-white hover:shadow-sm cursor-pointer"><input type="checkbox" class="mt-1 w-4 h-4 accent-thaco config-menu-check" value="\${item.id}" \${isChecked?'checked':''} \${isAll?'disabled':''}><div><div class="font-bold text-sm">\${item.name}</div><div class="text-xs text-gray-500">\${item.category||'Khác'}</div>\${isAll?'<span class="text-[10px] bg-gray-200 px-1 rounded">Mặc định (All)</span>':''}</div></label>\`}).join('')}async function saveLocationMenuConfig(){const checks=document.querySelectorAll('.config-menu-check');checks.forEach(chk=>{const item=masterMenu.find(i=>i.id==chk.value);if(item&&!item.locations.includes('all')){if(chk.checked){if(!item.locations.includes(currentEditingLocId))item.locations.push(currentEditingLocId)}else{item.locations=item.locations.filter(l=>l!==currentEditingLocId)}}});await fetch(API+'/saveMasterMenu',{method:'POST',headers:getHeaders(),body:JSON.stringify(masterMenu)});alert('Đã cập nhật!');closeModal('configMenuModal')}async function loadMenu(){const res=await fetch(API+'/getMasterMenu',{headers:getHeaders()});const json=await res.json();masterMenu=json.data||[];renderMenu();const cats=[...new Set(masterMenu.map(i=>i.category).filter(c=>c))];document.getElementById('catSuggestions').innerHTML=cats.map(c=>\`<option value="\${c}">\`).join('')}function renderMenu(){document.getElementById('menuList').innerHTML=masterMenu.map((item,i)=>\`<div class="border rounded-lg overflow-hidden bg-white shadow-sm flex flex-col group"><img src="\${item.image||'https://via.placeholder.com/200'}" class="h-32 object-cover w-full"><div class="p-3 flex-1"><div class="font-bold text-thaco truncate">\${item.name}</div><div class="flex flex-wrap gap-1 mt-1">\${item.tags?item.tags.map(tid=>{const t=masterTags.find(x=>x.id===tid);return t?\`<span class="px-1.5 py-0.5 text-[10px] rounded text-white" style="background-color:\${t.color}">\${t.name}</span>\`:''}).join(''):''}</div></div><div class="p-2 border-t flex justify-end gap-2 bg-gray-50"><button onclick="openMenuModal(\${i})" class="text-blue-600 font-bold text-xs uppercase">Sửa</button><button onclick="delMenu(\${i})" class="text-red-600 font-bold text-xs uppercase">Xóa</button></div></div>\`).join('')}async function loadTags(){const res=await fetch(API+'/getTags',{headers:getHeaders()});const json=await res.json();masterTags=json.data||[];renderTags()}function renderTags(){document.getElementById('tagsList').innerHTML=masterTags.map((t,i)=>\`<div class="flex items-center gap-2 p-2 border rounded bg-white"><div class="w-6 h-6 rounded border" style="background-color:\${t.color}"></div><div class="flex-1 font-bold">\${t.name} <span class="text-xs text-gray-400">(\${t.id})</span></div><button onclick="delTag(\${i})" class="text-red-500"><i class="fas fa-trash"></i></button></div>\`).join('')}async function addTag(){const id=prompt('Mã Tag (VD: hot, new):');if(!id)return;const name=prompt('Tên hiển thị (VD: Món Hot):');const color=prompt('Màu sắc (VD: #ff0000):', '#ff0000');if(id&&name&&color){masterTags.push({id:id.toLowerCase(),name,color});await fetch(API+'/saveTags',{method:'POST',headers:getHeaders(),body:JSON.stringify(masterTags)});loadTags()}}async function delTag(i){if(confirm('Xóa tag?')){masterTags.splice(i,1);await fetch(API+'/saveTags',{method:'POST',headers:getHeaders(),body:JSON.stringify(masterTags)});loadTags()}}function openMenuModal(index=null){openModal('menuModal');document.getElementById('optionsContainer').innerHTML='';if(index!==null){const item=masterMenu[index];document.getElementById('modalTitle').innerText='Sửa Món';document.getElementById('editIndex').value=index;document.getElementById('itemName').value=item.name;document.getElementById('itemCategory').value=item.category||'';document.getElementById('itemDesc').value=item.description||'';document.getElementById('itemImageUrl').value=item.image||'';document.getElementById('previewImg').src=item.image||'';document.getElementById('previewImg').classList.remove('hidden');if(item.options)item.options.forEach(g=>addOptionGroup(g));document.getElementById('tagsContainer').innerHTML=masterTags.map(t=>\`<label class="flex items-center gap-2 text-sm"><input type="checkbox" class="tag-check" value="\${t.id}" \${item.tags&&item.tags.includes(t.id)?'checked':''}> <span style="color:\${t.color}">\${t.name}</span></label>\`).join('')}else{document.getElementById('modalTitle').innerText='Thêm Món';document.getElementById('editIndex').value='-1';document.getElementById('itemName').value='';document.getElementById('itemCategory').value='';document.getElementById('itemDesc').value='';document.getElementById('itemImageUrl').value='';document.getElementById('previewImg').classList.add('hidden');document.getElementById('tagsContainer').innerHTML=masterTags.map(t=>\`<label class="flex items-center gap-2 text-sm"><input type="checkbox" class="tag-check" value="\${t.id}"> <span style="color:\${t.color}">\${t.name}</span></label>\`).join('')}}function addOptionGroup(g={group:'',choices:['']}){const d=document.createElement('div');d.className='border p-2 rounded bg-gray-50';d.innerHTML=\`<div class="flex gap-2 mb-1"><input value="\${g.group}" class="group-name flex-1 p-1 border text-sm font-bold" placeholder="Tên nhóm"><button onclick="this.closest('.border').remove()" class="text-red-500 text-xs">Xóa</button></div><div>\${g.choices.map(c=>\`<input value="\${c}" class="choice-name w-full p-1 border text-xs mb-1" placeholder="Lựa chọn">\`).join('')}</div><button onclick="addChoice(this)" class="text-blue-500 text-xs">+ Thêm lựa chọn</button>\`;document.getElementById('optionsContainer').appendChild(d)}function addChoice(btn){const i=document.createElement('input');i.className='choice-name w-full p-1 border text-xs mb-1';i.placeholder='Lựa chọn';btn.parentNode.insertBefore(i,btn)}async function saveMenuItem(){const idx=parseInt(document.getElementById('editIndex').value);const name=document.getElementById('itemName').value;const category=document.getElementById('itemCategory').value;const desc=document.getElementById('itemDesc').value;const img=document.getElementById('itemImageUrl').value;const tags=Array.from(document.querySelectorAll('.tag-check:checked')).map(c=>c.value);const options=[];document.querySelectorAll('#optionsContainer > div').forEach(div=>{const g=div.querySelector('.group-name').value;const c=Array.from(div.querySelectorAll('.choice-name')).map(i=>i.value).filter(v=>v);if(g&&c.length)options.push({group:g,choices:c})});if(!name)return alert('Thiếu tên');const oldLocs=(idx!==-1)?masterMenu[idx].locations:['all'];const item={id:(idx===-1?Date.now():masterMenu[idx].id),name,category,description:desc,image:img,locations:oldLocs,options,tags};if(idx===-1)masterMenu.push(item);else masterMenu[idx]=item;await fetch(API+'/saveMasterMenu',{method:'POST',headers:getHeaders(),body:JSON.stringify(masterMenu)});closeModal('menuModal');loadMenu()}async function delMenu(i){if(confirm('Xóa?')){masterMenu.splice(i,1);await fetch(API+'/saveMasterMenu',{method:'POST',headers:getHeaders(),body:JSON.stringify(masterMenu)});loadMenu()}}async function loadBanners(){const res=await fetch(API+'/getBanners',{headers:getHeaders()});const json=await res.json();banners=json.data||[];renderBanners()}function renderBanners(){document.getElementById('bannerList').innerHTML=banners.map((b,i)=>\`<div class="flex items-center p-3 bg-gray-50 border rounded"><img src="\${b.imageUrl}" class="w-24 h-12 object-cover mr-3"><div class="flex-1 overflow-hidden"><div class="font-bold truncate">\${b.linkUrl||'Không link'}</div><div class="text-xs">\${b.locationId}</div></div><div class="flex gap-1"><button onclick="editBanner(\${i})" class="text-blue-500">Sửa</button><button onclick="delBanner(\${i})" class="text-red-500">Xóa</button></div></div>\`).join('')}function openBannerModal(index=null){openModal('bannerModal');if(index!==null){const b=banners[index];document.getElementById('bannerModalTitle').innerText='Sửa Banner';document.getElementById('editBannerIndex').value=index;document.getElementById('bannerUrl').value=b.imageUrl;document.getElementById('bannerLink').value=b.linkUrl;document.getElementById('bannerLocSelect').value=b.locationId;document.getElementById('previewBanner').src=b.imageUrl;document.getElementById('previewBanner').classList.remove('hidden')}else{document.getElementById('bannerModalTitle').innerText='Thêm Banner';document.getElementById('editBannerIndex').value='-1';document.getElementById('bannerUrl').value='';document.getElementById('bannerLink').value='';document.getElementById('previewBanner').classList.add('hidden')}}function editBanner(i){openBannerModal(i)}async function saveBanner(){const idx=parseInt(document.getElementById('editBannerIndex').value);const img=document.getElementById('bannerUrl').value;const link=document.getElementById('bannerLink').value;const loc=document.getElementById('bannerLocSelect').value;if(!img)return alert('Thiếu ảnh');const item={locationId:loc,imageUrl:img,linkUrl:link};if(idx===-1)banners.push(item);else banners[idx]=item;await fetch(API+'/saveBanners',{method:'POST',headers:getHeaders(),body:JSON.stringify(banners)});closeModal('bannerModal');loadBanners()}async function delBanner(i){if(confirm('Xóa?')){banners.splice(i,1);await fetch(API+'/saveBanners',{method:'POST',headers:getHeaders(),body:JSON.stringify(banners)});loadBanners()}}async function loadReports(){const start=document.getElementById('reportStart').value;const end=document.getElementById('reportEnd').value;const locId=document.getElementById('reportLocSelect').value;if(!start||!end||!locId)return alert('Vui lòng chọn đủ thông tin');document.getElementById('reportResults').innerHTML='<p class="text-center py-10">Đang tải...</p>';try{const res=await fetch(API+'/getReportData',{method:'POST',headers:getHeaders(),body:JSON.stringify({locationId:locId,startDate:start,endDate:end})});const json=await res.json();if(json.success&&json.data.length>0){const orders=json.data;let html=\`<div class="grid grid-cols-2 gap-4 mb-4"><div class="bg-blue-50 p-4 rounded text-center"><div class="text-2xl font-bold text-blue-700">\${orders.length}</div><div class="text-xs text-blue-500">Tổng đơn</div></div><div class="bg-green-50 p-4 rounded text-center"><div class="text-2xl font-bold text-green-700">\${orders.filter(o=>o.status==='completed').length}</div><div class="text-xs text-green-500">Hoàn thành</div></div></div><table class="w-full text-sm text-left text-gray-500 border-collapse"><thead class="text-xs text-gray-700 uppercase bg-gray-100"><tr><th class="px-4 py-3">Ngày</th><th class="px-4 py-3">Tên</th><th class="px-4 py-3">SĐT</th><th class="px-4 py-3">Bàn</th><th class="px-4 py-3">Món</th><th class="px-4 py-3">Trạng thái</th></tr></thead><tbody>\`;orders.forEach(o=>{const items=o.items.map(i=>\`\${i.quantity}x \${i.name}\`).join(', ');const date=new Date(o.createdAt).toLocaleString('vi-VN');const statusMap={'pending':'Mới','preparing':'Đang làm','completed':'Xong','cancelled':'Hủy'};html+=\`<tr class="bg-white border-b hover:bg-gray-50"><td class="px-4 py-2 whitespace-nowrap">\${date}</td><td class="px-4 py-2 font-bold">\${o.customerName}</td><td class="px-4 py-2">\${o.phoneNumber||'-'}</td><td class="px-4 py-2">\${o.tableNumber}</td><td class="px-4 py-2 truncate max-w-xs" title="\${items}">\${items}</td><td class="px-4 py-2">\${statusMap[o.status]||o.status}</td></tr>\`});html+='</tbody></table>';document.getElementById('reportResults').innerHTML=html}else{document.getElementById('reportResults').innerHTML='<p class="text-center py-10">Không có dữ liệu.</p>'}}catch(e){alert('Lỗi: '+e)}}async function uploadImage(inputId,urlId,previewId){const file=document.getElementById(inputId).files[0];if(!file)return alert('Chưa chọn ảnh');const fd=new FormData();fd.append('file',file);try{const res=await fetch(API+'/uploadImage',{method:'POST',headers:{'x-admin-pass':localStorage.getItem('adminPass')},body:fd});const json=await res.json();if(json.success){document.getElementById(urlId).value=json.url;document.getElementById(previewId).src=json.url;document.getElementById(previewId).classList.remove('hidden')}}catch(e){alert('Lỗi: '+e)}}async function triggerExport(){if(!confirm('Xác nhận xuất toàn bộ đơn HÔM NAY sang Google Sheet?'))return;const btn=event.currentTarget;const original=btn.innerHTML;btn.disabled=true;btn.innerHTML='Đang xử lý...';try{const res=await fetch(API+'/triggerExport',{method:'POST',headers:getHeaders()});const json=await res.json();alert(json.success?'✅ '+json.message:'❌ '+json.message)}catch(e){alert('❌ Lỗi kết nối')}finally{btn.disabled=false;btn.innerHTML=original}}</script></body></html>`;
  
